import { 菩薩坐身, 上臂常勢, 前臂 } from './pusa.js';
import { 五化佛冠 } from './center-t.js';
import { 慧劍 } from '../bujian/sanmaya.js';
import { 手勢, 指寬 } from '../bujian/zhi.js';
import { 側拳, 臂釧, 腕釧 } from '../bujian/index.js';
export const 普賢菩薩 = (bi) => 菩薩坐身(bi, {
    月輪: false,
    冠: 五化佛冠,
    嚴先: true,
    臂(bi, 筆) {
        const { M, C, Qk, S, 骨, 衣, 細, 陰, 陽 } = 筆;
        骨(() => { 上臂常勢(筆, -1, 40.0); 上臂常勢(筆, 1, 40.2); });
        // 尊左：執蓮莖，蓮上立劍（莖蓮先落，劍立其上，拳覆莖）
        衣(() => {
            M(6.5, 41.6);
            C(6.2, 38.8, 6.0, 36.2, 5.9, 33.9);
            S();
            M(7.2, 41.5);
            C(6.95, 38.8, 6.85, 36.2, 6.8, 33.9);
            S();
            M(4.5, 33.9);
            Qk(5.1, 32.5, 5.9, 32.1);
            S();
            M(8.2, 33.85);
            Qk(7.7, 32.55, 6.95, 32.1);
            S();
            M(5.9, 32.1);
            Qk(6.4, 31.9, 6.95, 32.1);
            S();
        });
        慧劍(bi, 6.35, 29.5, 0.58);
        骨(() => 陰(() => 前臂(bi, 筆, [13.8, 40.3], [8.8, 41.9], { 寬根: 2.5, 寬梢: 1.9, 弓: -0.35, 肘帽: true })));
        側拳(bi, 6.8, 41.6, -0.25, 1.06, -1);
        // 尊右：三業妙善印——舉掌當胸，屈無名小指，伸拇頭中三指
        骨(() => 陽(() => 前臂(bi, 筆, [-13.7, 40.1], [-5.1, 36.4], { 寬根: 2.5, 寬梢: 1.9, 弓: 0.4, 肘帽: true })));
        {
            const s = 手勢(bi, -4.2, 32.9, 0.95);
            s.骨(() => {
                s.M(-1.55, 3.2);
                s.C(-2.15, 1.9, -2.25, 0.4, -1.75, -0.9);
                s.S();
                s.M(1.45, 3.25);
                s.Qk(2.05, 2.2, 1.95, 0.85);
                s.S();
            });
            s.衣(() => {
                const 頭 = s.指(-0.95, -1.0, -Math.PI / 2 + 0.06, [1.9, 1.4, 1.0], [0, 0.04, 0.06]);
                s.畫(頭, 指寬.根, 指寬.梢, { 紋: true });
                const 中 = s.指(0.1, -1.15, -Math.PI / 2, [2.05, 1.5, 1.05], [0, 0.03, 0.05]);
                s.畫(中, 指寬.根, 指寬.梢, { 紋: true });
                // 無名小指：屈——本節出而中節急折（三業妙善之相）
                const 無名 = s.指(1.0, -0.9, -Math.PI / 2 + 0.15, [1.15, 0.85], [0, 1.55]);
                s.畫(無名, 指寬.根, 指寬.梢, { 紋: true });
                const 小 = s.指(1.7, -0.55, -Math.PI / 2 + 0.22, [0.95, 0.7], [0, 1.65]);
                s.畫(小, 指寬.小根, 指寬.小梢, { 紋: true });
                const 拇 = s.指(-1.9, 0.6, -Math.PI / 2 - 0.52, [1.7, 1.3], [0, -0.15]);
                s.畫(拇, 指寬.拇根, 指寬.拇梢, { 紋: true });
            });
        }
        // 嚴
        臂釧(bi, -1, 12.1, 14.5, 33.4);
        臂釧(bi, 1, 12.1, 14.5, 33.4);
        細(() => {
            腕釧(bi, [[-6.6, 35.8, -5.9, 36.7, -5.2, 37.5], [-6.1, 35.2, -5.4, 36.1, -4.7, 36.9]], [-5.7, 36.2]);
            腕釧(bi, [[9.8, 40.8, 9.3, 41.9, 9.8, 43.1], [10.7, 41.0, 10.2, 42.1, 10.7, 43.3]], [10.4, 42.1]);
        });
    },
});
